section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/vui-iot-integration.json",
  "title": "VUI + IoT Integration",
  "type": "object",
  "required": [
    "artefact_id",
    "command_patterns",
    "scene_grammar",
    "partial_failure_handling",
    "undo_support",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "command_patterns": {
      "type": "array",
      "description": "list of {pattern, examples} covering direct/scene/query/conditional/scheduled",
      "minItems": 1
    },
    "scene_grammar": {
      "type": "array",
      "description": "named scenes with discoverable voice phrases",
      "minItems": 1
    },
    "partial_failure_handling": {
      "type": "object",
      "description": "per-pattern failure messages + retry policy"
    },
    "undo_support": {
      "type": "object",
      "description": "rollback grammar and time-window per command pattern"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
